#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2025/12/16# @Author : cyq# @File : notify# @Software: PyCharm# @Desc: 结果推送from dataclasses import dataclassfrom datetime import datetimeimport aiosmtplibfrom app.mapper.project.pushMapper import PushMapperfrom app.model.base import PushModelfrom common.httpxClient import HttpxClientfrom config import Configfrom enums import PushEnum, TaskResultfrom app.model.interfaceAPIModel.interfaceResultModel import InterfaceTaskResultfrom app.model.playUI import PlayTaskResultfrom typing import TypeVarfrom email.mime.multipart import MIMEMultipartfrom email.mime.text import MIMETextfrom utils import logResult = TypeVar('Result', bound=InterfaceTaskResult | PlayTaskResult)@dataclassclass NotifyInfo:    """    推送结果信息    """    flag: str  # "API" | "UI"    result_id: int    result_uid: str    starter: str    result: TaskResult    task_name: str    task_id: int    task_uid: str    project_id: int    total: int    success: int    fail: int    use_time: str    start_time: str    end_time: strdef wework_template(notify: "NotifyInfo"):    """    企业微信 信息模版    """    result_page_url = Config.report_url(target=notify.flag, result_id=notify.result_id)    task_page_url = Config.task_url(target=notify.flag, task_id=notify.task_id, project_id=notify.project_id)    if notify.result == TaskResult.FAIL:        result_info = "**结果**：<font color=\"warning\">❌ 异常</font> [点我查看详情]"    else:        result_info = "**结果**：<font color=\"info\">✅ 通过</font> [点我查看详情]"    result_info += result_page_url    _template = f"""              ## 自动化任务: <font> [{notify.task_name}]({task_page_url}) </font> 测试完成              > 执行人: {notify.starter}              > 执行用时：{notify.use_time}              > 执行用例数量：{notify.total}              > 成功：{notify.success}              > 失败：{notify.fail}              > {result_info}              """    return _templatedef email_template2(notify: "NotifyInfo"):    """    邮件信息模版    """    result_page_url = Config.report_url(target=notify.flag, result_id=notify.result_id)    task_page_url = Config.task_url(target=notify.flag, task_id=notify.task_id, project_id=notify.project_id)    Subject = f"自动化任务: <font> [{notify.task_name}]({task_page_url}) </font> 测试完成"    if notify.result == TaskResult.FAIL:        Subject += f"❌ 异常"        result_info = "**结果**：<font color=\"warning\">❌ 异常</font> [点我查看详情]"    else:        Subject += "✅ 通过"        result_info = "**结果**：<font color=\"info\">✅ 通过</font> [点我查看详情]"    result_info += result_page_url    _template = f"""              ## 自动化任务: <font> [{notify.task_name}]({task_page_url}) </font> 测试完成              > 执行人: {notify.starter}              > 执行用时：{notify.use_time}              > 执行用例数量：{notify.total}              > 成功：{notify.success}              > 失败：{notify.fail}              > {result_info}              """    return _template, Subjectdef email_template(notify: "NotifyInfo"):    """    邮件信息模版 - HTML版本    """    result_page_url = Config.report_url(target=notify.flag, result_id=notify.result_id)    task_page_url = Config.task_url(target=notify.flag, task_id=notify.task_id, project_id=notify.project_id)    # 邮件主题    Subject = f"自动化任务: [{notify.task_name}] 测试完成"    # 判断结果状态    if notify.result == TaskResult.FAIL:        result_text = "❌ 异常"        result_color = "#ff4d4f"  # 红色        result_bg_color = "#fff2f0"        result_icon = "❌"    else:        result_text = "✅ 通过"        result_color = "#52c41a"  # 绿色        result_bg_color = "#f6ffed"        result_icon = "✅"    # HTML模板    html_template = f"""<!DOCTYPE html><html><head>    <meta charset="utf-8">    <meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="font-family: 'Segoe UI', Arial, sans-serif; line-height: 1.6; color: #333; max-width: 600px; margin: 0 auto;">    <div style="background: linear-gradient(135deg, #1890ff 0%, #096dd9 100%); padding: 20px; border-radius: 8px 8px 0 0;">        <h1 style="color: white; margin: 0; font-size: 24px;">            🤖 自动化测试任务通知        </h1>    </div>    <div style="background: #fafafa; padding: 30px; border-radius: 0 0 8px 8px; border: 1px solid #e8e8e8; border-top: none;">        <!-- 任务标题 -->        <div style="margin-bottom: 25px;">            <h2 style="margin: 0 0 10px 0; color: #1890ff; font-size: 20px;">                {notify.task_name}            </h2>            <p style="margin: 0; color: #666;">                任务执行完成，执行人: <strong>{notify.starter}</strong>            </p>        </div>        <!-- 状态卡片 -->        <div style="background: {result_bg_color}; border-left: 4px solid {result_color};                     padding: 15px; margin: 20px 0; border-radius: 4px;">            <div style="display: flex; align-items: center; gap: 10px;">                <span style="font-size: 24px;">{result_icon}</span>                <div>                    <h3 style="margin: 0; color: {result_color}; font-size: 18px;">                        {result_text}                    </h3>                    <p style="margin: 5px 0 0 0; color: #666;">                        执行用时: <strong>{notify.use_time}</strong>                    </p>                </div>            </div>        </div>        <!-- 统计数据 -->        <div style="background: white; border: 1px solid #e8e8e8; border-radius: 8px; padding: 20px; margin: 20px 0;">            <h3 style="margin: 0 0 15px 0; color: #333; font-size: 16px;">                📊 执行统计            </h3>            <div style="display: grid; grid-template-columns: repeat(2, 1fr); gap: 15px;">                <div style="text-align: center;">                    <div style="font-size: 28px; font-weight: bold; color: #1890ff;">                        {notify.total}                    </div>                    <div style="color: #666; font-size: 14px;">                        总用例数                    </div>                </div>                <div style="text-align: center;">                    <div style="font-size: 28px; font-weight: bold; color: #52c41a;">                        {notify.success}                    </div>                    <div style="color: #666; font-size: 14px;">                        成功用例                    </div>                </div>                <div style="text-align: center;">                    <div style="font-size: 28px; font-weight: bold; color: #ff4d4f;">                        {notify.fail}                    </div>                    <div style="color: #666; font-size: 14px;">                        失败用例                    </div>                </div>                <div style="text-align: center;">                    <div style="font-size: 28px; font-weight: bold; color: #faad14;">                        {notify.success_rate if hasattr(notify, 'success_rate') else round(notify.success / notify.total * 100, 1) if notify.total > 0 else 0}%                    </div>                    <div style="color: #666; font-size: 14px;">                        成功率                    </div>                </div>            </div>        </div>        <!-- 操作按钮 -->        <div style="margin: 30px 0; text-align: center;">            <a href="{result_page_url}"                style="display: inline-block; background: #1890ff; color: white;                       text-decoration: none; padding: 12px 30px; border-radius: 6px;                       font-weight: bold; margin-right: 10px;">               🔍 查看测试报告            </a>            <a href="{task_page_url}"                style="display: inline-block; background: #f0f0f0; color: #333;                       text-decoration: none; padding: 12px 30px; border-radius: 6px;                       font-weight: bold;">               📋 查看任务详情            </a>        </div>        <!-- 额外信息 -->        <div style="margin-top: 30px; padding-top: 20px; border-top: 1px solid #e8e8e8;">            <p style="margin: 0; color: #999; font-size: 14px;">                💡 提示: 此邮件为系统自动发送，请勿直接回复。            </p>            <p style="margin: 10px 0 0 0; color: #999; font-size: 14px;">                ⏰ 发送时间: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}            </p>        </div>    </div></body></html>    """    # 同时生成纯文本版本（为不支持HTML的邮件客户端提供）    text_template = f"""            自动化任务通知            ==============                        任务名称: {notify.task_name}            执行人: {notify.starter}            执行用时: {notify.use_time}            执行结果: {result_text}                        执行统计:            - 总用例数: {notify.total}            - 成功用例: {notify.success}            - 失败用例: {notify.fail}                        查看报告: {result_page_url}            查看任务: {task_page_url}                        发送时间: {datetime.now().strftime('%Y-%m-%d %H:%M:%S')}            此邮件为系统自动发送，请勿直接回复。"""    return html_template, text_template, Subjectclass NotifyManager:    def __init__(self, notify_id):        self.notify_id = notify_id        self.api_sender = HttpxClient()    async def push(self, flag: str, task_result: "Result"):        notify_info = NotifyInfo(flag=flag, **task_result.notify)        push_config = await PushMapper.get_by_id(self.notify_id)        T = push_config.push_type        match T:            case PushEnum.Email:                await self.to_email(notify_info, push_config)            case PushEnum.DingTalk:                pass            case PushEnum.WeWork:                await self.to_wechat(notify_info, push_config)    async def to_wechat(self, notify: "NotifyInfo", push_config: PushModel, ):        """        企业微信发送        """        _ = {            "msgtype": "markdown",            "markdown": {                "content": wework_template(notify)            }        }        response = await self.api_sender(url=Config.WeChatBaseUrl,                                         method="post",                                         params={"key": push_config.push_value},                                         json=_,                                         headers={"Content-Type": "application/json"})        if response.is_success:            log.info(f"[NotifyManager]:send wechat success")        else:            log.error(f"[NotifyManager]:send wechat fail")    async def to_email(self, notify: NotifyInfo, push_config: PushModel):        """        邮箱发送        """        _html, _text, subject = email_template(notify)        # 设置邮件内容        msg = MIMEMultipart()        msg['From'] = Config.Email_Sender_Username        msg['To'] = push_config.push_value        msg['Subject'] = subject        html_part = MIMEText(_html, "html", "utf-8")        text_part = MIMEText(_text, "plain", "utf-8")        # 创建alternative部分（客户端显示HTML或纯文本）        alternative = MIMEMultipart("alternative")        alternative.attach(text_part)        alternative.attach(html_part)        msg.attach(alternative)        import ssl        context = ssl.create_default_context()        context.check_hostname = False  # 临时禁用主机名验证进行测试（不推荐在生产环境中使用）        context.verify_mode = ssl.CERT_NONE  # 临时禁用证书验证（不推荐在生产环境中使用）        try:            # 建立安全连接            async with aiosmtplib.SMTP(hostname=Config.Smtp_Server,                                       tls_context=context) as server:                # server.starttls()  # 启用 TLS 加密                # server.set_debuglevel(1)  # 启用调试输出                await server.login(Config.Email_Sender_Username, Config.Email_Sender_Password)  # 登录到邮件服务器                await server.send_message(msg)            log.info("[NotifyManager]: send email success")        except Exception as e:            log.error(f"[NotifyManager] send email error : {e}")